/**
 * MinPriorityQueue implementation for Dijkstra's algorithm.
 * Stores [cost, node]. Compares based on cost (index 0).
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _getParentIndex(i) {
        return Math.floor((i - 1) / 2);
    }

    _getLeftChildIndex(i) {
        return 2 * i + 1;
    }

    _getRightChildIndex(i) {
        return 2 * i + 2;
    }

    _compare(a, b) {
        // Compare based on cost (index 0)
        return a[0] - b[0];
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return min;
    }

    _bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this._getParentIndex(currentIndex);
            if (this._compare(this.heap[currentIndex], this.heap[parentIndex]) < 0) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let left = this._getLeftChildIndex(currentIndex);
            let right = this._getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            if (left <= lastIndex && this._compare(this.heap[left], this.heap[smallest]) < 0) {
                smallest = left;
            }
            if (right <= lastIndex && this._compare(this.heap[right], this.heap[smallest]) < 0) {
                smallest = right;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}

/**
 * Checks if a path exists from source to target using at most k heavy edges
 * given a threshold T.
 * @param {number} n Number of nodes.
 * @param {Array<Array<number>>} edges Edge list: [u, v, w].
 * @param {number} source Starting node.
 * @param {number} target Ending node.
 * @param {number} k Max allowed heavy edges.
 * @param {number} threshold The current threshold T.
 * @returns {boolean} True if a valid path exists, false otherwise.
 */
function canReach(n, edges, source, target, k, threshold) {
    if (source === target) return true;

    // Build adjacency list
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, w] of edges) {
        // Store [neighbor, cost]
        // Cost is 1 if heavy (w > threshold), 0 if light (w <= threshold)
        const cost_uv = w > threshold ? 1 : 0;
        const cost_vu = w > threshold ? 1 : 0;

        adj[u].push([v, cost_uv]);
        adj[v].push([u, cost_vu]);
    }

    // Dijkstra's algorithm to find minimum heavy edge count
    // dist[i] = minimum heavy edges needed to reach node i
    const INF = k + 1; // Since we only care if count <= k, k+1 is effectively infinity for this purpose
    const dist = Array(n).fill(INF);

    const pq = new MinPriorityQueue();

    dist[source] = 0;
    // Priority Queue stores [heavy_edge_count, node]
    pq.enqueue([0, source]);

    while (!pq.isEmpty()) {
        const [d, u] = pq.dequeue();

        if (d > dist[u]) {
            continue;
        }

        if (u === target) {
            // Found shortest path in terms of heavy edges
            return d <= k;
        }

        for (const [v, cost] of adj[u]) {
            const newDist = d + cost;

            if (newDist <= k && newDist < dist[v]) {
                dist[v] = newDist;
                pq.enqueue([newDist, v]);
            }
        }
    }

    // If we exit the loop without reaching target, check the final distance
    return dist[target] <= k;
}


function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    // 1. Determine the range for binary search on threshold T.
    // Minimum possible threshold is 0.
    // Maximum relevant threshold is 10^9 (max weight). Using 10^9 + 1 as upper bound 
    // ensures we test the state where all edges are light.

    let L = 0;
    let R = 10**9 + 2; // Search space [0, 10^9 + 1]. R is exclusive boundary.
    let minThreshold = -1;

    // 2. Binary Search
    while (L < R) {
        // M is the candidate threshold
        const M = L + Math.floor((R - L) / 2);

        if (canReach(n, edges, source, target, k, M)) {
            // M works. Store it and try for a smaller threshold.
            minThreshold = M;
            R = M;
        } else {
            // M does not work. We need a higher threshold to potentially turn heavy edges light.
            L = M + 1;
        }
    }

    return minThreshold;
}

